def fake_create(messages):
    last = messages[-1]["content"]
    replies = {"hi": "hello", "who are you?": "an assistant."}
    text = replies.get(last, "...")
    return {
        "role": "assistant",
        "content": [{"type": "text", "text": text}],
    }

def chat(history, new_message):
    history.append({"role": "user", "content": new_message})
    response = fake_create(history)
    reply = response["content"][0]["text"]
    history.append({"role": "assistant", "content": reply})
    return history

history = []
history = chat(history, "hi")
history = chat(history, "who are you?")
for turn in history:
    print(f"{turn['role']}: {turn['content']}")

